const dados = items.map(item => item.json);

// === Cálculos gerais ===
const valorGeral = dados.reduce((acc, item) => acc + parseFloat(item.total_valor || 0), 0);
const quantidadeGeral = dados.reduce((acc, item) => acc + parseInt(item.count || 0), 0);

const quantidadeAmazon = dados
  .filter(item => item.ClienteGrupo === "AMAZON SERVICOS")
  .reduce((acc, item) => acc + parseInt(item.count || 0), 0);

// === Lógica de Ordenação e Top 5 ===
let dadosOrdenados = [...dados].sort((a, b) =>
  parseFloat(b.total_valor || 0) - parseFloat(a.total_valor || 0)
);

const top5 = dadosOrdenados.slice(0, 5);
const outros = dadosOrdenados.slice(5);

const valorOutros = outros.reduce((acc, item) => acc + parseFloat(item.total_valor || 0), 0);
const quantidadeOutros = outros.reduce((acc, item) => acc + parseInt(item.count || 0), 0);

// === Função resumir nome ===
function resumirNome(nome) {
  if (!nome || typeof nome !== 'string') return "Cliente não informado";
  const nomeLimpo = nome.trim();
  const palavras = nomeLimpo.split(/\s+/);
  return palavras.length <= 2 ? nomeLimpo : palavras.slice(0, 2).join(" ") + "...";
}

// === Dados para o Gráfico ===
const categorias = [
  ...top5.map(item => resumirNome(item.ClienteGrupo)),
  `Outros (${outros.length})`
];

const valores = [
  ...top5.map(item => parseFloat(item.total_valor || 0)),
  valorOutros
];

// === Resumo por Data (COM ORDENAÇÃO CRONOLÓGICA) ===
const porData = {};
dados.forEach(item => {
  const data = item.Evento || "Sem data";
  if (!porData[data]) {
    porData[data] = { quantidade: 0, valor: 0 };
  }
  porData[data].quantidade += parseInt(item.count || 0);
  porData[data].valor += parseFloat(item.total_valor || 0);
});

// Ordenar as chaves de data cronologicamente
const porDataOrdenada = Object.entries(porData).sort((a, b) => {
  if (a[0] === "Sem data") return 1;
  if (b[0] === "Sem data") return -1;
  // Converte DD/MM/YYYY para YYYYMMDD para comparação
  const pad = (d) => d.split('/').reverse().join('');
  return pad(a[0]).localeCompare(pad(b[0]));
});

// === HTML com Estilo Original Restaurado ===
const html = `
