return [{ json: { html } }];

// Entrada: items vindos do Postgres
// Saída: agrupado por matricula_motorista

const dados = items.map(item => item.json);

// Agrupar por matricula_motorista
const agrupado = {};

for (const registro of dados) {
  const matricula = registro.matricula_motorista;
  const numero = registro.Número;

  if (!agrupado[matricula]) {
    agrupado[matricula] = [];
  }
  agrupado[matricula].push(numero);
}

// Transformar em array de objetos
const resultado = Object.entries(agrupado).map(([matricula, numeros]) => {
  return {
    json: {
      matricula_motorista: matricula,
      numeros: numeros.join(",") // string separada por vírgula
    }
  };
});

return resultado;
